#include <bits/stdc++.h>
using namespace std;
int Find(unsigned long long n){
    int i=63;
    while((1LL<<i)>=n){
        i--;
    }
    if(i%2!=0){
        i--;
    }
    return i;
}
int main(){
    cin.tie(0)->sync_with_stdio(false);
    unsigned long long num;
    cin>>num;
    int r=Find(num);
    cout<<r;
    return 0;
}
